import React from 'react'
import {useState} from 'react'
import './App.css'

function App() {

  // const[name,setName] = useState("");
  // const[department,setDepartment] = useState("");
  // const[salary,setSalary] = useState("");

  const[formData,setData] = useState({employeeName:"",department:"",salary:""});

  const[arr,setArr] = useState([]);

  let handleChange = (e)=>
  {
    setData({...formData,[e.target.name]:e.target.value})
  }

  let addData = (e)=>
  {
    e.preventDefault();

    setArr([...arr,formData])


  }

  let handleReset =()=>
  {
    setArr([]);
    setData({employeeName:"",department:"",salary:""})
  }
  
console.log(arr);
  return (
    <>
      <h3>Employee form</h3>
      <form>

        <label>EMPLOYEE NAME</label>
        <input type="text" name="employeeName" onChange={handleChange}/> <br />

        <label>DEPARTMENT</label>
        <input type="text" name="department" onChange={handleChange}/> <br />

        <label>SALARY</label>
        <input type="number" name="salary" onChange={handleChange}/> <br />

        <button type="submit" onClick={addData}>Submit</button>
        <button type="reset" onClick={handleReset}>Reset</button>

      </form>

      <div id="container">
        {arr.map((obj,i)=>
        {
          return(
            <div key={i}>
            <h3>Employee Detail: </h3>
            <p>Name: {obj.employeeName}</p>
            <p>Department: {obj.department}</p>
            <p>Salary: {obj.salary}</p>
            </div>
          )
        })}
      </div>
    </>
  )
}

export default App

let handlechange = (e)=>{
  setData({...formData,[e.target.name]:e.target.value})
}